#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;
uniform int u_frame;
in vec2 v_uv;
out vec4 fragColor;

#define PI 3.14159265359
#define MAX_DIST 100.0
#define MAX_STEPS 100
#define SURF_DIST 0.001

struct Material {
  vec3 albedo;
  float roughness;
  float metallic;
  float emission;
  float ior;
};

struct Hit {
  float t;
  vec3 position;
  vec3 normal;
  Material material;
  int objectId;
};

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float hash3(vec3 p) {
  return fract(sin(dot(p, vec3(127.1, 311.7, 74.7))) * 43758.5453);
}

vec3 randomDirection(vec2 seed) {
  float z = 1.0 - 2.0 * hash(seed);
  float r = sqrt(1.0 - z * z);
  float phi = 2.0 * PI * hash(seed + 42.0);
  return vec3(r * cos(phi), r * sin(phi), z);
}

vec2 aspectCorrect(vec2 uv, vec2 res) {
  return (gl_FragCoord.xy * 2.0 - res) / min(res.x, res.y);
}

Hit miss() {
  Hit h;
  h.t = MAX_DIST;
  h.position = vec3(0.0);
  h.normal = vec3(0.0);
  h.material.albedo = vec3(0.0);
  h.material.roughness = 0.0;
  h.material.metallic = 0.0;
  h.material.emission = 0.0;
  h.material.ior = 1.0;
  h.objectId = -1;
  return h;
}

